#include <stdio.h>
#define N 3

void inverse_gaussjordan(float A[N][2*N]) {
    int i, j, k;
    float ratio;

    // Augment with Identity
    for(i=0; i<N; i++) {
        for(j=0; j<N; j++) A[i][j+N] = (i==j);
    }

    // Gauss-Jordan elimination
    for(i=0; i<N; i++) {
        if(A[i][i]==0) { printf("Singular\n"); return; }
        for(j=0; j<N; j++) {
            if(i!=j) {
                ratio = A[j][i]/A[i][i];
                for(k=0; k<2*N; k++)
                    A[j][k] -= ratio*A[i][k];
            }
        }
    }
    // Normalize rows
    for(i=0; i<N; i++) {
        for(j=N; j<2*N; j++)
            A[i][j] /= A[i][i];
    }
    // A[i][N to 2N-1] contains inverse
}
